library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity DATA is
	generic(
	DATA_WIDTH : integer := 2 -- Bits per I/Q per symbol
	);
	
	port(
	CLK : in std_logic;
	RST : in std_logic;
	
	RDY : in std_logic;
	
	VALID_OUT : out std_logic;
	
	OUTPUT_RE : out std_logic_vector(DATA_WIDTH-1 downto 0);
	OUTPUT_IM : out std_logic_vector(DATA_WIDTH-1 downto 0));
end DATA;

architecture RTL of DATA is
		
	constant LOREM : std_logic_vector(0 to 8191) := "";
	
	constant N : integer := LOREM'length;
	
	constant STRIDE : integer := (DATA_WIDTH*2);
	
	signal INDEX : integer range 0 to N-1 := 0;
	
	
	
begin

	process(CLK)
	variable TMP_RE : std_logic_vector(DATA_WIDTH-1 downto 0);
	variable TMP_IM : std_logic_vector(DATA_WIDTH-1 downto 0);
	begin
		if rising_edge(CLK) then
			if (RST = '1') then
				INDEX <= 0;
				VALID_OUT <= '0';

				OUTPUT_RE <= (others => '0');
				OUTPUT_IM <= (others => '0');
			else
				if (RDY = '1') then
				
					for i in 0 to DATA_WIDTH-1 loop
						TMP_RE(DATA_WIDTH-1-i) := LOREM((INDEX+i) mod N);
						TMP_IM(DATA_WIDTH-1-i) := LOREM((INDEX+DATA_WIDTH+i) mod N);
					end loop;
				
					OUTPUT_RE <= TMP_RE;
					OUTPUT_IM <= TMP_IM;
					VALID_OUT <= '1';
					INDEX <= (INDEX + STRIDE) MOD N;
				else
					OUTPUT_RE <= (others => '0');
					OUTPUT_IM <= (others => '0');
					VALID_OUT <= '0';	
				end if;
			end if;
		end if;
	end process;

end RTL;
